import React, { useState } from 'react';
import './Contact.css';

export default function Contact({ navigate }) {
  const [form, setForm] = useState({ name: '', email: '', phone: '', subject: '', msg: '' });
  const [sent, setSent] = useState(false);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      // FormSubmit endpoint -直接用 random string
      const response = await fetch('https://formsubmit.co/ajax/27a84a5d10c8b72fb274e40b7f45b117', {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          _subject: `New Contact Form Submission from ${form.name}`,
          name: form.name,
          email: form.email,
          phone: form.phone || 'Not provided',
          subject: form.subject || 'No Subject',
          message: form.msg,
          _template: 'table',
          _captcha: 'false'
        })
      });

      const result = await response.json();

      if (result.success) {
        setSent(true);
        setForm({ name: '', email: '', phone: '', subject: '', msg: '' });
      } else {
        alert('Failed to send message. Please try again.');
      }
    } catch (error) {
      alert('Network error. Please check your connection and try again.');
      console.error('Error:', error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fdct-page">
      <div className="fdct-hero">
        <span>Get In Touch</span>
        <h1>Contact <span>Us</span></h1>
        <p>Have a question? Need a quote? Our team is ready to help 24×7.</p>
      </div>

      <section className="fdct-content fd-section">
        <div className="fd-container fdct-grid">
          {/* Left Side - Contact Info */}
          <div className="fdct-info">
            <h2>Let's Talk</h2>
            <p>Whether you're a small business owner or managing a large fleet, our team will find the right fuel solution for you.</p>

            <div className="fdct-contact-items">
              <div className="fdct-item">
                <div className="fdct-item-icon">
                  <i className="fa fa-phone"></i>
                </div>
                <div>
                  <strong>Call Us</strong>
                  <span>+91-8088994444</span>
                  <span>Mon–Sat 8AM – 8PM</span>
                </div>
              </div>

              <div className="fdct-item">
                <div className="fdct-item-icon">
                  <i className="fa fa-envelope"></i>
                </div>
                <div>
                  <strong>Email Us</strong>
                  <span>support@fueldrop.in</span>
                  <span>Response within 2 hours</span>
                </div>
              </div>

              <div className="fdct-item">
                <div className="fdct-item-icon">
                  <i className="fa fa-map-marker-alt"></i>
                </div>
                <div>
                  <strong>Head Office</strong>
                  <span>Tower B, Quattro Towers</span>
                  <span>Udyog Vihar Phase 4, Gurugram 122016</span>
                </div>
              </div>
            </div>
          </div>

          {/* Right Side - Contact Form */}
          <div className="fdct-form-wrap">
            {sent ? (
              <div className="fdct-success">
                <div className="fdct-success-icon">✅</div>
                <h3>Message Sent!</h3>
                <p>Thank you for reaching out. Our team will contact you within 2 business hours.</p>
                <button onClick={() => setSent(false)}>Send Another Message</button>
              </div>
            ) : (
              <form className="fdct-form" onSubmit={handleSubmit}>
                <h3>Send a Message</h3>

                <div className="fdct-row">
                  <div className="fdct-field">
                    <label>Full Name *</label>
                    <input 
                      type="text"
                      required 
                      placeholder="Ramesh Kumar" 
                      value={form.name} 
                      onChange={e => setForm({...form, name: e.target.value})}
                      disabled={loading}
                    />
                  </div>

                  <div className="fdct-field">
                    <label>Email *</label>
                    <input 
                      type="email" 
                      required 
                      placeholder="you@example.com" 
                      value={form.email} 
                      onChange={e => setForm({...form, email: e.target.value})}
                      disabled={loading}
                    />
                  </div>
                </div>

                <div className="fdct-row">
                  <div className="fdct-field">
                    <label>Phone</label>
                    <input 
                      type="tel" 
                      placeholder="+91 98765 43210" 
                      value={form.phone} 
                      onChange={e => setForm({...form, phone: e.target.value})}
                      disabled={loading}
                    />
                  </div>

                  <div className="fdct-field">
                    <label>Subject</label>
                    <input 
                      type="text" 
                      placeholder="Fuel Delivery Enquiry" 
                      value={form.subject} 
                      onChange={e => setForm({...form, subject: e.target.value})}
                      disabled={loading}
                    />
                  </div>
                </div>

                <div className="fdct-field">
                  <label>Message *</label>
                  <textarea 
                    required 
                    rows="5" 
                    placeholder="Tell us about your fuel requirements..." 
                    value={form.msg} 
                    onChange={e => setForm({...form, msg: e.target.value})}
                    disabled={loading}
                  />
                </div>

                <button 
                  type="submit" 
                  className="fdct-submit" 
                  disabled={loading}
                >
                  {loading ? 'Sending...' : 'Send Message'} 
                  {!loading && <i className="fa fa-arrow-right"></i>}
                </button>
              </form>
            )}
          </div>
        </div>
      </section>
    </div>
  );
}
